import React, { useState } from 'react';
import axios from 'axios';
import Editor from '@monaco-editor/react';
import { Upload, FileCode, ShieldCheck, RefreshCw, Eye, EyeOff } from 'lucide-react';
import RiskProfile from './components/RiskProfile';

function App() {
  // --- State Management ---
  const [file, setFile] = useState(null);
  const [code, setCode] = useState("// Upload a PHP file to begin analysis...");
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [editorRef, setEditorRef] = useState(null);
  const [viewMode, setViewMode] = useState("original"); // Toggle between 'original' and 'normalized'

  // --- File Handling ---
  const handleFileUpload = (e) => {
    const uploadedFile = e.target.files[0];
    if (uploadedFile) {
      setFile(uploadedFile);
      const reader = new FileReader();
      reader.onload = (e) => setCode(e.target.result);
      reader.readAsText(uploadedFile);
      setResults(null); // Clear previous results when new file is loaded
    }
  };

  // --- Semantic Highlighting Logic ---
  const applyHighlights = (evidence) => {
    if (!editorRef || !evidence || !window.monaco) return;

    const decorations = evidence.map(item => ({
      range: new window.monaco.Range(item.line, 1, item.line, 1),
      options: {
        isWholeLine: true,
        className: 'bg-red-900/30', 
        glyphMarginClassName: 'bg-red-500 rounded-full',
        hoverMessage: { value: `**Semantic Warning:** Potential ${item.intent} detected.` }
      }
    }));

    // Apply new decorations to the editor instance
    editorRef.deltaDecorations([], decorations);
  };

  // --- API Interaction ---
  const analyzeMalware = async () => {
    if (!file) return alert("Please select a file first!");
    
    setLoading(true);
    const formData = new FormData();
    formData.append("file", file);

    try {
      const response = await axios.post("http://localhost:8000/scan", formData);
      const scanResults = response.data.results;
      setResults(scanResults);
      
      // If the backend identified specific malicious lines, highlight them
      if (scanResults.evidence) {
        applyHighlights(scanResults.evidence);
      }
    } catch (error) {
      console.error("Analysis failed", error);
      alert("Error connecting to PHPSentinel backend.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] text-slate-300 font-sans selection:bg-blue-500/30">
      {/* Navigation Bar */}
      <nav className="border-b border-slate-800 bg-[#1e293b]/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-[1600px] mx-auto px-6 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-blue-600 rounded-lg shadow-[0_0_20px_rgba(37,99,235,0.3)]">
              <ShieldCheck className="text-white" size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight text-white">PHPSentinel</h1>
              <p className="text-[10px] uppercase tracking-widest text-blue-400 font-black">AI Malware Intelligence</p>
            </div>
          </div>
          
          <div className="flex items-center gap-4">
            <label className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-full cursor-pointer transition-all text-sm font-medium">
              <Upload size={16} className="text-blue-400" />
              <span>{file ? file.name : "Select PHP Script"}</span>
              <input type="file" className="hidden" onChange={handleFileUpload} accept=".php" />
            </label>
            <button 
              onClick={analyzeMalware}
              disabled={loading}
              className="px-6 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-full text-sm font-bold shadow-lg shadow-blue-900/20 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50"
            >
              {loading ? <RefreshCw className="animate-spin" size={16} /> : "Run Intelligence Scan"}
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-[1600px] mx-auto p-6 grid grid-cols-12 gap-6">
        {/* Code Viewport (Col 1-8) */}
        <div className="col-span-12 lg:col-span-8 space-y-4">
          <div className="bg-[#1e293b] rounded-2xl border border-slate-800 overflow-hidden shadow-2xl">
            <div className="bg-slate-900/50 px-5 py-3 border-b border-slate-800 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <div className="flex gap-1.5">
                  <div className="w-3 h-3 rounded-full bg-red-500/20 border border-red-500/50"></div>
                  <div className="w-3 h-3 rounded-full bg-yellow-500/20 border border-yellow-500/50"></div>
                  <div className="w-3 h-3 rounded-full bg-green-500/20 border border-green-500/50"></div>
                </div>
                {/* Fixed ESLint Warning: Using FileCode here */}
                <div className="flex items-center gap-2 ml-4">
                  <FileCode size={14} className="text-slate-500" />
                  <span className="text-xs font-mono text-slate-500 uppercase tracking-widest">
                    {viewMode === 'original' ? 'raw_payload.php' : 'deobfuscated_output.php'}
                  </span>
                </div>
              </div>

              {/* View Toggle */}
              <div className="flex gap-1 bg-slate-900 p-1 rounded-xl border border-slate-800">
                <button 
                  onClick={() => setViewMode("original")}
                  className={`flex items-center gap-2 px-3 py-1.5 text-[10px] uppercase font-black rounded-lg transition-all ${viewMode === 'original' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  <EyeOff size={12} /> Raw
                </button>
                <button 
                  onClick={() => setViewMode("normalized")}
                  className={`flex items-center gap-2 px-3 py-1.5 text-[10px] uppercase font-black rounded-lg transition-all ${viewMode === 'normalized' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/40' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  <Eye size={12} /> Normalized
                </button>
              </div>
            </div>
            
            <div className="h-[70vh]">
              <Editor
                height="100%"
                defaultLanguage="php"
                theme="vs-dark"
                value={results ? (viewMode === "original" ? results.original_code : results.normalized_code) : code}
                onMount={(editor) => setEditorRef(editor)}
                options={{ 
                  readOnly: true, 
                  minimap: { enabled: false },
                  fontSize: 14,
                  fontFamily: "'Fira Code', monospace",
                  glyphMargin: true,
                  renderLineHighlight: 'all',
                  scrollBeyondLastLine: false,
                  lineNumbers: 'on',
                  padding: { top: 20 }
                }}
              />
            </div>
          </div>
        </div>

        {/* Intelligence Sidebar (Col 9-12) */}
        <div className="col-span-12 lg:col-span-4 h-full">
          {results ? (
            <div className="animate-in fade-in slide-in-from-right duration-500">
              <RiskProfile data={results} />
            </div>
          ) : (
            <div className="h-full min-h-[500px] flex flex-col items-center justify-center bg-[#1e293b]/20 border-2 border-dashed border-slate-800 rounded-3xl p-12 text-center transition-all hover:bg-[#1e293b]/40">
              <div className="w-24 h-24 bg-slate-800/50 rounded-full flex items-center justify-center mb-8 border border-slate-700 animate-pulse shadow-inner">
                <ShieldCheck size={48} className="text-slate-700" />
              </div>
              <h3 className="text-xl font-bold text-slate-300">Ready for Analysis</h3>
              <p className="text-sm text-slate-500 mt-3 max-w-[240px] leading-relaxed">
                Provide a PHP script to identify semantic behavioral patterns and estimate threat risk levels.
              </p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

export default App;
